import React, { createContext, useContext, useState, useEffect } from 'react';
import { darkTheme, lightTheme } from '../styles/theme';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('finify-theme');
    return saved ? saved === 'dark' : true;
  });

  useEffect(() => {
    const root = window.document.documentElement;
    const currentTheme = isDarkMode ? darkTheme : lightTheme;

    // 🛡️ SAFETY GUARD: Check if currentTheme exists before converting to entries
    if (!currentTheme) return;

    Object.entries(currentTheme).forEach(([prop, val]) => {
      root.style.setProperty(prop, val);
    });

    root.setAttribute('data-theme', isDarkMode ? 'dark' : 'light');
    localStorage.setItem('finify-theme', isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // We provide the object directly to ensure it is never null in the hook
  const value = { isDarkMode, toggleTheme, theme: isDarkMode ? darkTheme : lightTheme };

  return (
    <ThemeContext.Provider value={value}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};
